/// Trait for handling Session domain events
///
/// All handler methods receive the event sequence number for tracking
/// which events have been processed by the projector.
#[async_trait]
pub trait SessionEventHandler: Send + Sync {
    /// Handle entity created event
    async fn on_created(&self, event: SessionCreatedEvent, sequence: i64) -> Result<()>;
    /// Handle entity updated event
    async fn on_updated(&self, event: SessionUpdatedEvent, sequence: i64) -> Result<()>;
    /// Handle entity deleted event
    async fn on_deleted(&self, event: SessionDeletedEvent, sequence: i64) -> Result<()>;
}

