/// Repository for Session projections
#[async_trait]
pub trait SessionProjectionRepository: Send + Sync {
    async fn save(&self, projection: &SessionProjection) -> Result<()>;
    async fn find_by_id(&self, id: uuid::Uuid) -> Result<Option<SessionProjection>>;
    async fn delete(&self, id: uuid::Uuid) -> Result<()>;
    async fn rebuild_all(&self) -> Result<u64>;
}

