/// Projector that updates Session projection from events
pub struct SessionProjector<R: SessionProjectionRepository> {
    repository: Arc<R>,
}

impl<R: SessionProjectionRepository> SessionProjector<R> {
    /// Create a new projector
    pub fn new(repository: Arc<R>) -> Self {
        Self { repository }
    }

    /// Rebuild all projections from event history
    pub async fn rebuild(&self) -> Result<u64> {
        self.repository.rebuild_all().await
    }

    /// Process a stored event from the event store
    ///
    /// This method dispatches the event to the appropriate handler based on event type.
    /// Returns Ok(true) if the event was processed, Ok(false) if it was skipped.
    pub async fn process_stored_event(&self, event: &crate::infrastructure::event_store::StoredEvent) -> Result<bool>
    where
        Self: SessionEventHandler,
    {
        let sequence = event.sequence;

        match event.event_type.as_str() {
            "SessionCreatedEvent" => {
                let created: SessionCreatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_created(created, sequence).await?;
                Ok(true)
            }
            "SessionUpdatedEvent" => {
                let updated: SessionUpdatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_updated(updated, sequence).await?;
                Ok(true)
            }
            "SessionDeletedEvent" => {
                let deleted: SessionDeletedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_deleted(deleted, sequence).await?;
                Ok(true)
            }
            _ => Ok(false), // Event type not handled by this projector
        }
    }
}

#[async_trait]
impl<R: SessionProjectionRepository> SessionEventHandler for SessionProjector<R> {

    async fn on_created(&self, event: SessionCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = SessionProjection::new(
            event.id,
            event.user_id,
            event.token_hash,
            event.expires_at,
            event.extended_at,
            event.remember_me,
            event.last_activity,
            event.ip_address,
            event.user_agent,
            event.device_type,
            event.device_fingerprint,
            event.is_active,
            event.revoked_at,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: SessionUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.token_hash = event.token_hash;
            projection.expires_at = event.expires_at;
            projection.extended_at = event.extended_at;
            projection.remember_me = event.remember_me;
            projection.last_activity = event.last_activity;
            projection.ip_address = event.ip_address;
            projection.user_agent = event.user_agent;
            projection.device_type = event.device_type;
            projection.device_fingerprint = event.device_fingerprint;
            projection.is_active = event.is_active;
            projection.revoked_at = event.revoked_at;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: SessionDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

